CREATE SCHEMA IF NOT EXISTS ledger;

CREATE OR REPLACE FUNCTION ledger._entry_balanced(p_entry_id integer)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_count integer;
  v_sum_debit numeric(12,2);
  v_sum_credit numeric(12,2);
BEGIN
  SELECT count(*), coalesce(sum(debit), 0), coalesce(sum(credit), 0)
    INTO v_count, v_sum_debit, v_sum_credit
    FROM ledger.entry_line
   WHERE journal_entry_id = p_entry_id;

  IF v_count < 2 THEN RETURN false; END IF;
  RETURN v_sum_debit = v_sum_credit;
END;
$function$;
COMMENT ON FUNCTION ledger._entry_balanced(integer) IS 'Check if a journal entry is balanced (SUM debit = SUM credit, at least 2 lines)';

CREATE OR REPLACE FUNCTION ledger._protect_posted()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF TG_OP = 'DELETE' THEN
        IF OLD.posted THEN
            RAISE EXCEPTION 'Écriture validée : suppression interdite (id=%)', OLD.id;
        END IF;
        RETURN OLD;
    END IF;
    IF OLD.posted AND NEW.posted THEN
        RAISE EXCEPTION 'Écriture validée : modification interdite (id=%)', OLD.id;
    END IF;
    IF NEW.posted AND NOT OLD.posted THEN
        NEW.posted_at := now();
    END IF;
    RETURN NEW;
END;
$function$;
DROP TRIGGER IF EXISTS trg_protect_posted ON ledger.journal_entry;
CREATE TRIGGER trg_protect_posted BEFORE DELETE OR UPDATE ON ledger.journal_entry FOR EACH ROW EXECUTE FUNCTION ledger._protect_posted();

CREATE OR REPLACE FUNCTION ledger._protect_posted_lines()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_posted BOOLEAN;
BEGIN
    IF TG_OP = 'DELETE' THEN
        SELECT posted INTO v_posted FROM ledger.journal_entry WHERE id = OLD.journal_entry_id;
    ELSE
        SELECT posted INTO v_posted FROM ledger.journal_entry WHERE id = NEW.journal_entry_id;
    END IF;
    IF v_posted THEN
        RAISE EXCEPTION 'Écriture validée : modification des lignes interdite';
    END IF;
    IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
    RETURN NEW;
END;
$function$;
DROP TRIGGER IF EXISTS trg_protect_posted_lines ON ledger.entry_line;
CREATE TRIGGER trg_protect_posted_lines BEFORE INSERT OR DELETE OR UPDATE ON ledger.entry_line FOR EACH ROW EXECUTE FUNCTION ledger._protect_posted_lines();

CREATE OR REPLACE FUNCTION ledger._type_label(p_type text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN CASE p_type
    WHEN 'asset'     THEN pgv.t('ledger.type_asset')
    WHEN 'liability' THEN pgv.t('ledger.type_liability')
    WHEN 'equity'    THEN pgv.t('ledger.type_equity')
    WHEN 'revenue'   THEN pgv.t('ledger.type_revenue')
    WHEN 'expense'   THEN pgv.t('ledger.type_expense')
    ELSE p_type
  END;
END;
$function$;
COMMENT ON FUNCTION ledger._type_label(text) IS 'Translate account type to localized label';

CREATE OR REPLACE FUNCTION ledger._type_sign(p_type text)
 RETURNS integer
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  RETURN CASE
    WHEN p_type IN ('asset', 'expense') THEN 1
    WHEN p_type IN ('liability', 'equity', 'revenue') THEN -1
    ELSE NULL
  END;
END;
$function$;
COMMENT ON FUNCTION ledger._type_sign(text) IS 'Returns 1 for debit-normal accounts (asset/expense), -1 for credit-normal (liability/equity/revenue)';

CREATE OR REPLACE FUNCTION ledger._account_balance(p_account_id integer, p_date date DEFAULT NULL::date)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_type text;
  v_sign integer;
  v_balance numeric;
BEGIN
  SELECT type INTO v_type FROM ledger.account WHERE id = p_account_id;
  IF NOT FOUND THEN RETURN 0; END IF;

  v_sign := ledger._type_sign(v_type);

  SELECT coalesce(sum(el.debit) - sum(el.credit), 0)
    INTO v_balance
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
   WHERE el.account_id = p_account_id
     AND je.posted = true
     AND (p_date IS NULL OR je.entry_date <= p_date);

  RETURN v_sign * v_balance;
END;
$function$;
COMMENT ON FUNCTION ledger._account_balance(integer,date) IS 'Account balance respecting debit/credit normal sign. Optional date filter.';

CREATE OR REPLACE FUNCTION ledger._period_total(p_type text, p_start date, p_end date)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_sign integer;
  v_total numeric;
BEGIN
  v_sign := ledger._type_sign(p_type);

  SELECT coalesce(sum(el.debit) - sum(el.credit), 0)
    INTO v_total
    FROM ledger.entry_line el
    JOIN ledger.journal_entry je ON je.id = el.journal_entry_id
    JOIN ledger.account a ON a.id = el.account_id
   WHERE a.type = p_type
     AND je.posted = true
     AND je.entry_date >= p_start
     AND je.entry_date <= p_end;

  RETURN v_sign * v_total;
END;
$function$;
COMMENT ON FUNCTION ledger._period_total(text,date,date) IS 'Sum of balances for all accounts of a given type within a date range';

CREATE OR REPLACE FUNCTION ledger.account_create(p_row ledger.account)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  p_row.tenant_id := current_setting('app.tenant_id', true);
  p_row.active := coalesce(p_row.active, true);
  p_row.created_at := now();

  INSERT INTO ledger.account (code, label, type, parent_code, active, tenant_id, created_at)
  VALUES (p_row.code, p_row.label, p_row.type, p_row.parent_code, p_row.active, p_row.tenant_id, p_row.created_at)
  RETURNING * INTO p_row;

  RETURN to_jsonb(p_row);
END;
$function$;
COMMENT ON FUNCTION ledger.account_create(ledger.account) IS 'Create a new account in the chart of accounts';

CREATE OR REPLACE FUNCTION ledger.account_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row ledger.account;
BEGIN
  IF EXISTS (SELECT 1 FROM ledger.entry_line WHERE account_id = p_id::int) THEN
    RAISE EXCEPTION 'Account has entry lines, cannot delete (id=%)', p_id;
  END IF;

  DELETE FROM ledger.account
  WHERE id = p_id::int
    AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO v_row;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Account not found (id=%)', p_id;
  END IF;

  RETURN to_jsonb(v_row);
END;
$function$;
COMMENT ON FUNCTION ledger.account_delete(text) IS 'Delete an account (fails if entry lines reference it)';

CREATE OR REPLACE FUNCTION ledger.account_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN QUERY
    SELECT to_jsonb(a) || jsonb_build_object(
      'balance', coalesce(sum(el.debit) - sum(el.credit), 0),
      'type_label', ledger._type_label(a.type)
    )
    FROM ledger.account a
    LEFT JOIN ledger.entry_line el ON el.account_id = a.id
    WHERE a.tenant_id = current_setting('app.tenant_id', true)
    GROUP BY a.id
    ORDER BY a.code;
END;
$function$;
COMMENT ON FUNCTION ledger.account_list(text) IS 'List accounts enriched with computed balance';

CREATE OR REPLACE FUNCTION ledger.account_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_result jsonb;
BEGIN
  SELECT to_jsonb(a) || jsonb_build_object(
    'balance', coalesce(sum(el.debit) - sum(el.credit), 0),
    'line_count', count(el.id)
  ) INTO v_result
  FROM ledger.account a
  LEFT JOIN ledger.entry_line el ON el.account_id = a.id
  WHERE (a.id = p_id::int OR a.code = p_id)
    AND a.tenant_id = current_setting('app.tenant_id', true)
  GROUP BY a.id;

  IF v_result IS NULL THEN RETURN NULL; END IF;

  -- HATEOAS actions based on state
  IF (v_result->>'line_count')::int = 0 THEN
    v_result := v_result || jsonb_build_object('actions', jsonb_build_array(
      jsonb_build_object('method', 'delete', 'uri', 'ledger://account/' || (v_result->>'id'))
    ));
  ELSE
    v_result := v_result || jsonb_build_object('actions', '[]'::jsonb);
  END IF;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION ledger.account_read(text) IS 'Read account by id or code with computed balance and line count';

CREATE OR REPLACE FUNCTION ledger.account_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_account jsonb;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('ledger.nav_accounts')),
        pgv.ui_table('accounts', jsonb_build_array(
          pgv.ui_col('code', pgv.t('ledger.col_code'), pgv.ui_link('{code}', '/ledger/accounts/{id}')),
          pgv.ui_col('label', pgv.t('ledger.col_label')),
          pgv.ui_col('type_label', pgv.t('ledger.col_type'), pgv.ui_badge('{type_label}')),
          pgv.ui_col('balance', pgv.t('ledger.col_balance')),
          pgv.ui_col('active', pgv.t('ledger.col_active'), pgv.ui_badge('{active}'))
        ))
      ),
      'datasources', jsonb_build_object(
        'accounts', pgv.ui_datasource('ledger://account', 30, true, 'code')
      )
    );
  END IF;

  -- Detail mode
  v_account := ledger.account_read(p_slug);
  IF v_account IS NULL THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      pgv.ui_row(
        pgv.ui_link(E'\u2190 ' || pgv.t('ledger.nav_accounts'), '/ledger/accounts'),
        pgv.ui_heading((v_account->>'code') || ' — ' || (v_account->>'label'))
      ),
      pgv.ui_row(
        pgv.ui_badge(ledger._type_label(v_account->>'type')),
        pgv.ui_badge(
          CASE WHEN (v_account->>'active')::boolean THEN pgv.t('ledger.badge_active') ELSE pgv.t('ledger.badge_inactive') END,
          CASE WHEN (v_account->>'active')::boolean THEN 'success' ELSE 'error' END
        )
      ),
      pgv.ui_row(
        pgv.ui_text(pgv.t('ledger.col_balance') || ' : ' || (v_account->>'balance')),
        pgv.ui_text(pgv.t('ledger.col_lines') || ' : ' || (v_account->>'line_count'))
      )
    )
  );
END;
$function$;
COMMENT ON FUNCTION ledger.account_ui(text) IS 'SDUI view: account list + detail';

CREATE OR REPLACE FUNCTION ledger.account_update(p_row ledger.account)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE ledger.account
  SET code = coalesce(p_row.code, code),
      label = coalesce(p_row.label, label),
      type = coalesce(p_row.type, type),
      parent_code = p_row.parent_code,
      active = coalesce(p_row.active, active)
  WHERE id = p_row.id
    AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO p_row;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Account not found (id=%)', p_row.id;
  END IF;

  RETURN to_jsonb(p_row);
END;
$function$;
COMMENT ON FUNCTION ledger.account_update(ledger.account) IS 'Update an account in the chart of accounts';

CREATE OR REPLACE FUNCTION ledger.account_view()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN jsonb_build_object(
    'uri', 'ledger://account',
    'label', 'ledger.entity_account',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
        'fields', jsonb_build_array('code', 'label', 'type')
      ),

      'standard', jsonb_build_object(
        'fields', jsonb_build_array('code', 'label', 'type', 'active'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'balance', 'label', 'ledger.col_balance'),
          jsonb_build_object('key', 'line_count', 'label', 'ledger.col_lines')
        )
      ),

      'expanded', jsonb_build_object(
        'fields', jsonb_build_array('code', 'label', 'type', 'parent_code', 'active', 'created_at'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'balance', 'label', 'ledger.col_balance'),
          jsonb_build_object('key', 'line_count', 'label', 'ledger.col_lines')
        )
      ),

      'form', jsonb_build_object(
        'sections', jsonb_build_array(
          jsonb_build_object('label', 'ledger.section_account', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'code', 'label', 'ledger.col_code', 'type', 'text', 'required', true),
            jsonb_build_object('key', 'label', 'label', 'ledger.col_label', 'type', 'text', 'required', true),
            jsonb_build_object('key', 'type', 'label', 'ledger.col_type', 'type', 'select', 'required', true,
              'options', jsonb_build_array(
                jsonb_build_object('label', 'ledger.type_asset', 'value', 'asset'),
                jsonb_build_object('label', 'ledger.type_liability', 'value', 'liability'),
                jsonb_build_object('label', 'ledger.type_equity', 'value', 'equity'),
                jsonb_build_object('label', 'ledger.type_revenue', 'value', 'revenue'),
                jsonb_build_object('label', 'ledger.type_expense', 'value', 'expense')
              )),
            jsonb_build_object('key', 'parent_code', 'label', 'ledger.field_parent_code', 'type', 'text'),
            jsonb_build_object('key', 'active', 'label', 'ledger.col_active', 'type', 'checkbox')
          ))
        )
      )
    ),

    'actions', jsonb_build_object(
      'delete', jsonb_build_object('label', 'ledger.btn_delete', 'variant', 'danger', 'confirm', 'ledger.confirm_delete_account')
    )
  );
END;
$function$;
COMMENT ON FUNCTION ledger.account_view() IS 'View template for account: compact, standard, expanded, form, actions';

