$function$;
COMMENT ON FUNCTION ledger.i18n_seed() IS 'Seed French translations for ledger module into pgv.i18n';

CREATE OR REPLACE FUNCTION ledger.journal_entry_create(p_row ledger.journal_entry)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  p_row.tenant_id := current_setting('app.tenant_id', true);
  p_row.posted := false;
  p_row.created_at := now();

  INSERT INTO ledger.journal_entry (entry_date, reference, description, posted, tenant_id, created_at)
  VALUES (coalesce(p_row.entry_date, CURRENT_DATE), p_row.reference, p_row.description, p_row.posted, p_row.tenant_id, p_row.created_at)
  RETURNING * INTO p_row;

  RETURN to_jsonb(p_row);
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_create(ledger.journal_entry) IS 'Create a new journal entry (draft)';

CREATE OR REPLACE FUNCTION ledger.journal_entry_delete(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row ledger.journal_entry;
BEGIN
  DELETE FROM ledger.journal_entry
  WHERE id = p_id::int
    AND tenant_id = current_setting('app.tenant_id', true)
    AND NOT posted
  RETURNING * INTO v_row;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Entry not found or already posted (id=%)', p_id;
  END IF;

  RETURN to_jsonb(v_row);
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_delete(text) IS 'Delete a draft journal entry (posted entries cannot be deleted)';

CREATE OR REPLACE FUNCTION ledger.journal_entry_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN QUERY
    SELECT to_jsonb(je) || jsonb_build_object(
      'total_debit', coalesce(sum(el.debit), 0),
      'total_credit', coalesce(sum(el.credit), 0),
      'line_count', count(el.id),
      'status', CASE WHEN je.posted THEN 'posted' ELSE 'draft' END
    )
    FROM ledger.journal_entry je
    LEFT JOIN ledger.entry_line el ON el.journal_entry_id = je.id
    WHERE je.tenant_id = current_setting('app.tenant_id', true)
    GROUP BY je.id
    ORDER BY je.entry_date DESC, je.id DESC;
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_list(text) IS 'List journal entries enriched with debit/credit totals and line count';

CREATE OR REPLACE FUNCTION ledger.journal_entry_read(p_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_entry record;
  v_lines jsonb;
  v_result jsonb;
  v_balanced boolean;
BEGIN
  SELECT * INTO v_entry FROM ledger.journal_entry
  WHERE id = p_id::int AND tenant_id = current_setting('app.tenant_id', true);
  IF NOT FOUND THEN RETURN NULL; END IF;

  SELECT coalesce(jsonb_agg(to_jsonb(r) ORDER BY r.id), '[]'::jsonb) INTO v_lines
  FROM (
    SELECT el.id, el.account_id, a.code AS account_code, a.label AS account_label,
           el.debit, el.credit, el.label
    FROM ledger.entry_line el
    JOIN ledger.account a ON a.id = el.account_id
    WHERE el.journal_entry_id = v_entry.id
    ORDER BY el.id
  ) r;

  v_result := to_jsonb(v_entry) || jsonb_build_object(
    'lines', v_lines,
    'status', CASE WHEN v_entry.posted THEN 'posted' ELSE 'draft' END
  );

  -- HATEOAS actions based on state
  v_balanced := ledger._entry_balanced(v_entry.id);
  IF NOT v_entry.posted THEN
    IF v_balanced THEN
      v_result := v_result || jsonb_build_object('actions', jsonb_build_array(
        jsonb_build_object('method', 'post', 'uri', 'ledger://journal_entry/' || p_id || '/post'),
        jsonb_build_object('method', 'delete', 'uri', 'ledger://journal_entry/' || p_id)
      ));
    ELSE
      v_result := v_result || jsonb_build_object('actions', jsonb_build_array(
        jsonb_build_object('method', 'delete', 'uri', 'ledger://journal_entry/' || p_id)
      ));
    END IF;
  ELSE
    v_result := v_result || jsonb_build_object('actions', '[]'::jsonb);
  END IF;

  RETURN v_result;
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_read(text) IS 'Read journal entry by id with lines enriched with account code/label';

CREATE OR REPLACE FUNCTION ledger.journal_entry_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_entry jsonb;
BEGIN
  -- List mode
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('ledger.nav_entries')),
        pgv.ui_table('entries', jsonb_build_array(
          pgv.ui_col('entry_date', pgv.t('ledger.col_date')),
          pgv.ui_col('reference', pgv.t('ledger.col_reference'), pgv.ui_link('{reference}', '/ledger/entries/{id}')),
          pgv.ui_col('description', pgv.t('ledger.col_description')),
          pgv.ui_col('total_debit', pgv.t('ledger.col_amount')),
          pgv.ui_col('status', pgv.t('ledger.col_status'), pgv.ui_badge('{status}'))
        ))
      ),
      'datasources', jsonb_build_object(
        'entries', pgv.ui_datasource('ledger://journal_entry', 20, true, 'entry_date')
      )
    );
  END IF;

  -- Detail mode
  v_entry := ledger.journal_entry_read(p_slug);
  IF v_entry IS NULL THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      pgv.ui_row(
        pgv.ui_link(E'\u2190 ' || pgv.t('ledger.nav_entries'), '/ledger/entries'),
        pgv.ui_heading(v_entry->>'reference')
      ),
      pgv.ui_row(
        pgv.ui_text(pgv.t('ledger.col_date') || ' : ' || (v_entry->>'entry_date')),
        pgv.ui_badge(
          CASE WHEN (v_entry->>'posted')::boolean THEN pgv.t('ledger.badge_posted') ELSE pgv.t('ledger.badge_draft') END,
          CASE WHEN (v_entry->>'posted')::boolean THEN 'success' ELSE 'warning' END
        )
      ),
      pgv.ui_text(v_entry->>'description')
    )
  );
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_ui(text) IS 'SDUI view: journal entry list + detail';

CREATE OR REPLACE FUNCTION ledger.journal_entry_update(p_row ledger.journal_entry)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  UPDATE ledger.journal_entry
  SET entry_date = coalesce(p_row.entry_date, entry_date),
      reference = coalesce(p_row.reference, reference),
      description = coalesce(p_row.description, description)
  WHERE id = p_row.id
    AND tenant_id = current_setting('app.tenant_id', true)
    AND NOT posted
  RETURNING * INTO p_row;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Entry not found or already posted (id=%)', p_row.id;
  END IF;

  RETURN to_jsonb(p_row);
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_update(ledger.journal_entry) IS 'Update a draft journal entry (posted entries are immutable)';

CREATE OR REPLACE FUNCTION ledger.journal_entry_view()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN jsonb_build_object(
    'uri', 'ledger://journal_entry',
    'label', 'ledger.entity_journal_entry',

    'template', jsonb_build_object(
      'compact', jsonb_build_object(
        'fields', jsonb_build_array('reference', 'entry_date', 'status')
      ),

      'standard', jsonb_build_object(
        'fields', jsonb_build_array('reference', 'entry_date', 'description', 'total_debit', 'total_credit'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'line_count', 'label', 'ledger.col_lines'),
          jsonb_build_object('key', 'total_debit', 'label', 'ledger.col_debit'),
          jsonb_build_object('key', 'total_credit', 'label', 'ledger.col_credit')
        )
      ),

      'expanded', jsonb_build_object(
        'fields', jsonb_build_array('reference', 'entry_date', 'description', 'total_debit', 'total_credit', 'posted', 'posted_at', 'created_at'),
        'stats', jsonb_build_array(
          jsonb_build_object('key', 'line_count', 'label', 'ledger.col_lines'),
          jsonb_build_object('key', 'total_debit', 'label', 'ledger.col_debit'),
          jsonb_build_object('key', 'total_credit', 'label', 'ledger.col_credit')
        ),
        'related', jsonb_build_array(
          jsonb_build_object('entity', 'quote://invoice', 'filter', 'id={invoice_id}', 'label', 'ledger.related_invoice'),
          jsonb_build_object('entity', 'expense://expense_report', 'filter', 'id={expense_note_id}', 'label', 'ledger.related_expense_note')
        )
      ),

      'form', jsonb_build_object(
        'sections', jsonb_build_array(
          jsonb_build_object('label', 'ledger.section_entry', 'fields', jsonb_build_array(
            jsonb_build_object('key', 'entry_date', 'label', 'ledger.field_date', 'type', 'date', 'required', true),
            jsonb_build_object('key', 'reference', 'label', 'ledger.field_reference', 'type', 'text', 'required', true),
            jsonb_build_object('key', 'description', 'label', 'ledger.field_description', 'type', 'text', 'required', true)
          ))
        )
      )
    ),

    'actions', jsonb_build_object(
      'post', jsonb_build_object('label', 'ledger.btn_post', 'variant', 'primary', 'confirm', 'ledger.confirm_post_entry'),
      'delete', jsonb_build_object('label', 'ledger.btn_delete', 'variant', 'danger', 'confirm', 'ledger.confirm_delete_draft')
    )
  );
END;
$function$;
COMMENT ON FUNCTION ledger.journal_entry_view() IS 'View template for journal_entry: compact, standard, expanded, form, actions';

CREATE OR REPLACE FUNCTION ledger.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('href', '/', 'label', pgv.t('ledger.nav_dashboard'), 'icon', 'home'),
    jsonb_build_object('href', '/entries', 'label', pgv.t('ledger.nav_entries'), 'icon', 'list', 'entity', 'journal_entry', 'uri', 'ledger://journal_entry'),
    jsonb_build_object('href', '/accounts', 'label', pgv.t('ledger.nav_accounts'), 'icon', 'book', 'entity', 'account', 'uri', 'ledger://account'),
    jsonb_build_object('href', '/balance', 'label', pgv.t('ledger.nav_balance'), 'icon', 'scale'),
    jsonb_build_object('href', '/fiscal_year', 'label', pgv.t('ledger.nav_fiscal_year'), 'icon', 'calendar'),
    jsonb_build_object('href', '/vat', 'label', pgv.t('ledger.nav_vat'), 'icon', 'percent'),
    jsonb_build_object('href', '/balance_sheet', 'label', pgv.t('ledger.nav_balance_sheet'), 'icon', 'bar-chart')
  );
$function$;
COMMENT ON FUNCTION ledger.nav_items() IS 'Navigation items for Ledger module';

